<?php
namespace App\Domain\Hunts;
use App\Domain\Characters\CharacterStatsCalculator;use App\Domain\Combat\CombatSide;use App\Domain\Combat\CombatSimulator;use App\Domain\Combat\Factories\CharacterCombatantFactory;use App\Domain\Combat\Factories\MonsterCombatantFactory;use App\Domain\Hunts\Data\EncounterEnemy;use App\Domain\Hunts\Data\HuntEnemyResult;use App\Domain\Hunts\Data\HuntResult;use App\Domain\Hunts\Exceptions\InvalidHuntingZoneException;use App\Domain\Hunts\Sessions\Data\HuntExecutionContext;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Character;use App\Models\Hunt;use App\Models\Zone;use App\Models\ZoneEncounterSize;use Illuminate\Support\Collection;use Illuminate\Support\Facades\DB;use InvalidArgumentException;use RuntimeException;
final class HuntService{private $sizeSelector;private $monsterSelector;private $calculator;private $characterFactory;private $monsterFactory;private $combat;private $persister;public function __construct(EncounterSizeSelector $size,WeightedMonsterSelector $monster,CharacterStatsCalculator $calculator,CharacterCombatantFactory $characterFactory,MonsterCombatantFactory $monsterFactory,CombatSimulator $combat,HuntEnemyPersister $persister){$this->sizeSelector=$size;$this->monsterSelector=$monster;$this->calculator=$calculator;$this->characterFactory=$characterFactory;$this->monsterFactory=$monsterFactory;$this->combat=$combat;$this->persister=$persister;}
 public function start(Character $character,Zone $zone):HuntResult{if(!$character->exists||!$zone->exists)throw new InvalidArgumentException('Persisted entities required.');return DB::transaction(function()use($character,$zone){$locked=Character::whereKey($character->id)->lockForUpdate()->firstOrFail();return$this->executeLocked($locked,$zone,null);},3);}
 /** Character and HuntingSession must already be locked inside the caller transaction. */
 public function startForLockedSession(Character $lockedCharacter,Zone $zone,HuntExecutionContext $context):HuntResult{return$this->executeLocked($lockedCharacter,$zone,$context);}
 private function executeLocked(Character $c,Zone $zone,HuntExecutionContext $context=null){$started=now();$z=Zone::whereKey($zone->id)->lockForUpdate()->firstOrFail();if($z->status!==CatalogStatus::ACTIVE||!$z->allows_hunting)throw new InvalidHuntingZoneException('Esta zona no permite cacerías.');$configs=ZoneEncounterSize::where('zone_id',$z->id)->orderBy('sort_order')->orderBy('id')->lockForUpdate()->get();$count=$this->sizeSelector->select($configs);$eligible=$this->monsterSelector->eligibleEntries($z,$c);$selected=$this->monsterSelector->selectMany($eligible,$count);$encounter=[];foreach($selected as $i=>$monster){$position=$i+1;$identifier='monster:'.$monster->id.':'.$position;$encounter[]=new EncounterEnemy($identifier,$position,$monster->id,$monster->code,$monster->name,$this->monsterFactory->make($monster,$identifier));}$player=$this->characterFactory->make($c,$this->calculator->calculate($c));$result=$this->combat->simulateEncounter($player,array_map(function($enemy){return$enemy->combatantStats();},$encounter));$playerResult=$result->participant($player->identifier());if(!$playerResult)throw new RuntimeException('Player combat result missing.');$enemyResults=[];foreach($result->participants() as $participant){if($participant->sideIdentifier()!==CombatSide::ENEMIES)continue;$id=$participant->identifier();if(isset($enemyResults[$id]))throw new RuntimeException('Duplicate enemy result identifier.');$enemyResults[$id]=$participant;}if(count($enemyResults)!==count($encounter))throw new RuntimeException('Unexpected enemy result count.');$hunt=Hunt::create(['hunting_session_id'=>$context?$context->huntingSessionId():null,'character_id'=>$c->id,'character_name'=>$c->name,'zone_id'=>$z->id,'zone_name'=>$z->name,'enemy_count'=>count($encounter),'status'=>$result->status(),'rounds_count'=>$result->roundsCount(),'character_health_before'=>$playerResult->initialHealth(),'character_health_after'=>$playerResult->finalHealth(),'started_at'=>$started,'completed_at'=>now()]);$created=[];$seen=[];foreach($encounter as $enemy){$id=$enemy->instanceIdentifier();if(!isset($enemyResults[$id]))throw new RuntimeException('Enemy combat result missing.');$participant=$enemyResults[$id];unset($enemyResults[$id]);$created[]=$this->persister->create($hunt,['monster_id'=>$enemy->monsterId(),'position'=>$enemy->position(),'instance_identifier'=>$id,'monster_code_snapshot'=>$enemy->monsterCodeSnapshot(),'monster_name_snapshot'=>$enemy->monsterNameSnapshot(),'initial_health'=>$participant->initialHealth(),'final_health'=>$participant->finalHealth(),'status'=>HuntEnemyStatus::fromFinalHealth($participant->finalHealth())]);$seen[$id]=true;}if($enemyResults||count($created)!==$hunt->enemy_count||count($seen)!==$hunt->enemy_count)throw new RuntimeException('Persisted encounter invariant failed.');foreach($created as $i=>$row)if($row->position!==$i+1)throw new RuntimeException('Enemy positions are not consecutive.');$hunt->setRelation('enemies',collect($created));return$this->entry($hunt);}
 public function history(Character $character,int $limit=50):Collection{return$character->hunts()->with('enemies')->latest()->limit($limit)->get()->map(function($hunt){return$this->entry($hunt);});}public function detail(Character $character,$huntId):HuntResult{return$this->entry($character->hunts()->with('enemies')->whereKey($huntId)->firstOrFail());}private function entry(Hunt $hunt){$enemies=$hunt->enemies->map(function($enemy){return new HuntEnemyResult($enemy->position,$enemy->instance_identifier,$enemy->monster_id,$enemy->monster_code_snapshot,$enemy->monster_name_snapshot,$enemy->initial_health,$enemy->final_health,$enemy->status);})->all();return new HuntResult($hunt->id,$hunt->character_id,$hunt->character_name,$hunt->zone_id,$hunt->zone_name,$hunt->status,$hunt->rounds_count,$hunt->character_health_before,$hunt->character_health_after,$hunt->enemy_count,$enemies,$hunt->started_at->toIso8601String(),$hunt->completed_at->toIso8601String());}}
